var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤. 주변에 반응은?","JPN":"サシャ、周りに反応は？","ENG":"Sasha, are there any signals around us?","TWN":"莎夏。周圍還有反應嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"없어. 상황종료야!","JPN":"ない。オールオッケーだよ！","ENG":"Nope! It's all clear!","TWN":"沒有。已經結束了！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"믿을 수가 없네. 맨손으로 침식체들을 박살 내다니…!","JPN":"信じられない。侵食体を素手でぶちのめした……！","ENG":"Unbelievable. She defeated those C.O.s with her bare hands...!","TWN":"不敢相信，居然能徒手擊敗侵蝕體……！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"뭐 하는 녀석이지? 그 몸은 대체 뭐고?","JPN":"いったい何者？　その体はどうなってるの？","ENG":"Who is she? And what's up with her body?","TWN":"她是什麼人？那副身體到底是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그만하세요 올가 언니! 얘는 제 친구예요!","JPN":"ちょっと、止めてくださいオルガさん！　この子は私の友だちです！","ENG":"Stop it, Olga! She's my friend!","TWN":"住手，歐嘉姊姊！她是我的朋友！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"친구라고?","JPN":"友だち？","ENG":"Your friend?","TWN":"朋友？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"으엑… 너도 친구가 있었어? 라는 말투…","JPN":"そんな……あなた、友だちいたの？って言い方……","ENG":"Egh... that I-can't-believe-you-have-friends tone...","TWN":"呃……怎麼一副懷疑的語氣……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"어이 사샤, 매번 뭔갈 만들더니, 진짜 대단한 걸 가져왔네?","JPN":"おい、サシャ。しょっちゅう何か作ってると思ったら、今回は本当にすごいものを持ってきたじゃないか！","ENG":"Hey, Sasha. You always were making something, and it seems like you brought something truly amazing this time.","TWN":"喂，莎夏，你每天自己在那邊弄東弄西的，結果還真的弄出個這麼厲害的東西啊？！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"저번엔 그리 대단한 건 못 만든다면서, 우릴 속인 거야?","JPN":"この前は大したもの作れないって言っておいて、あれは嘘だったのか？","ENG":"Did you fool us by saying that you couldn't make anything good last time?","TWN":"對啊！上次還說沒辦法，不會是在騙我們吧？哈哈！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다들 물러서.","JPN":"全員、下がって。","ENG":"Everyone, step back.","TWN":"都給我退後。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"으음?!","JPN":"えっ！？","ENG":"Mmm?!","TWN":"唔？！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"괜찮아 마브카. 이분들은 모두 내 동료들이야.","JPN":"大丈夫だよ、マブカ。この人たちは皆私の仲間だから。","ENG":"It's okay, Mavka. These people are all my friends.","TWN":"沒關係，瑪卡。這些人都是我的同伴。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"전투를 치루고 나면 흥분이 가시지 않아서 말이야. 소개가 늦었군.","JPN":"戦闘後は昂ぶりがなかなか収まらなくてな。自己紹介が遅れてしまったな。","ENG":"It takes me a while to calm down after a battle. Guess I forgot to introduce myself.","TWN":"喔……戰鬥結束後情緒還沒平復過來。忘了介紹了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"우린 시린그라드의 민병단이다. 저쪽은 안드레이 형님, 그리고 이쪽은 올가 누님이지.","JPN":"俺たちはシリングラードの民兵団だ。あっちはアンドレイの兄貴、こっちはオルガの姉貴だ。","ENG":"We are Ciringrad's militia. That's Andrei over there, and this is Olga.","TWN":"我們是錫林格勒的民兵團。那位是安德烈，安哥，這位是歐嘉，歐姊。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"넌 이름이 뭐냐.","JPN":"お前は？","ENG":"What's your name?","TWN":"你叫什麼名字。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……마브카.","JPN":"……マブカ。","ENG":"...Mavka.","TWN":"……瑪卡。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"동화에서나 듣던 이름 같은데?","JPN":"おとぎ話とかで聞いた名前だな。","ENG":"Sounds like a name from a fairytale.","TWN":"聽起來像是童話裡的名字？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"어쨌든 대단한 힘이구만! 우리도 그런 팔 하나쯤 있었으면 좋았을 텐데.","JPN":"まあとにかく、大した実力だったぞ！　俺もそんな腕一本ぐらいあればな。","ENG":"Anyway, that was some feat! I wish I had an arm like that.","TWN":"不管怎樣，真是了不起！要是我們也有一隻這樣的手臂就好了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아니, 본래의 절반도 내지 못했어.","JPN":"いや、本来の力の半分も出せなかった。","ENG":"No, that wasn't even half of my powers.","TWN":"不，我還沒發揮出原本力量的一半。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그러고보니 너 포스터에서 본 녀석들과 비슷한 것 같은데…","JPN":"そういえばあなた……ポスターで見たやつらと似てる気がするんだけど……","ENG":"Come to think of it, you look like one of the girls from the poster...","TWN":"說起來，你好像和海報上的那些傢伙很像……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"설마 북방군이야? 여긴 무슨 일로 왔지?","JPN":"まさか北方軍？　ここには何をしに来たの？","ENG":"Are you from the Northern Army? What brings you here?","TWN":"難道是北方軍的人？你來這裡幹什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"오해에요 언니. 마브카는 침식지대에 있던 절 구해줬다구요!","JPN":"オルガさん、誤解です！　マブカは侵食地帯で私を助けてくれたんですよ！","ENG":"That's a misunderstanding, Olga. Mavka saved me when I was in the Corrupted Area!","TWN":"誤會了，姊姊。瑪卡在侵蝕區救了我！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"앗……!","JPN":"あっ……！","ENG":"Oops...!","TWN":"糟糕……！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"사샤 너. 침식지대에 혼자 가지 말라고 그렇게 말했는데…!","JPN":"サシャ、一人で侵食地帯に行っちゃだめだとあれほど言ったのに……！","ENG":"Sasha, didn't I tell you to not go in the Corrupted Area alone...?!","TWN":"莎夏，我不是說過不要一個人去侵蝕區嗎……！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};